const out = [];

for (const item of $input.all()) {
  const p = item.json.payload ?? {};
  const info = p._data?.Info ?? {};

  // --- Filter: abaikan grup & pesan dari bot sendiri ---
  const fromMe = p.fromMe ?? info.IsFromMe ?? false;
  const isGroup = info.IsGroup ?? false;
  if (fromMe || isGroup) continue;

  // --- Nomor asli pelanggan ---
  const altRaw = info.SenderAlt || '';
  let phone = altRaw.split('@')[0].split(':')[0];
  const fromRaw = String(p.from || '');
  if (!phone && !fromRaw.includes('@lid')) {
    phone = fromRaw.split('@')[0].split(':')[0];
  }

  // --- Deteksi tipe & isi ---
  const rawType = String(info.Type || info.MediaType || '').toLowerCase();
  const msg = p._data?.Message ?? {};
  let type = 'text';
  let mediaUrl = '';
  let body = p.body || p._data?.RawMessage?.conversation || '';

  if (p.hasMedia || rawType) {
    if (rawType === 'image' || msg.imageMessage) {
      type = 'image';
    } else if (rawType === 'video' || msg.videoMessage) {
      type = 'video';
    } else if (rawType === 'audio' || rawType === 'ptt' || msg.audioMessage || msg.pttMessage) {
      type = 'audio'; // termasuk voice note (ptt)
    } else if (rawType === 'document' || msg.documentMessage) {
      type = 'document';
    } else if (rawType && rawType !== 'text') {
      type = 'document'; // sticker/lainnya → document
    }

    if (type !== 'text') {
      body =
        p.body ||
        msg.imageMessage?.caption ||
        msg.videoMessage?.caption ||
        msg.documentMessage?.caption ||
        '';
      const media = p.media;
      mediaUrl = typeof media === 'string' ? media : (media?.url || p.mediaUrl || '');
    }
  }

  out.push({
    json: {
      session: item.json.session,
      chatId: p.from,
      messageId: p.id || info.ID,
      customerPhone: phone,
      customerName: info.PushName || '',
      type,                 // text | image | video | audio | document
      body,
      mediaUrl,
      fromMe,
      isGroup,
    },
  });
}

return out;

const ctx = $input.first().json;

const produk = ctx.dataBarang || [];
const info   = ctx.dataToko || [];
const promo  = ctx.dataPromo || [];

// Ambil 10 chat terakhir
const riwayatRaw = (ctx.riwayat || []).slice(0, 10);

const fase   = ctx.fase || 'none';
const orderStatus = ctx.orderStatus || 'none';

// Format Produk (variants sekarang JSON: [{name, images:[]}])
const dataBarangStr = produk.length
  ? produk.map(p => {
      let text = `- ${p.name} | Rp${Number(p.price||0).toLocaleString('id-ID')} | stok: ${p.stock ?? '-'}`;

      if (p.description) {
        let desc = p.description.length > 100 ? p.description.substring(0, 100) + '...' : p.description;
        text += `\n  Desc: ${desc}`;
      }

      // Foto utama produk (image_url, bisa multi-baris)
      if (p.image_url) {
        const mainImgs = String(p.image_url).split('\n').map(u => u.trim()).filter(Boolean);
        if (mainImgs.length) text += `\n  Foto Utama: ${mainImgs.join(', ')}`;
      }

      // Varian (JSON) → nama + foto per varian
      if (p.variants) {
        try {
          const vars = JSON.parse(p.variants);
          if (Array.isArray(vars) && vars.length) {
            text += `\n  Varian:`;
            for (const v of vars) {
              const imgs = (v.images || []).filter(Boolean);
              text += `\n    • ${v.name || 'varian'}${imgs.length ? ` (foto: ${imgs.join(', ')})` : ''}`;
            }
          }
        } catch {
          // fallback kalau variants masih teks lama
          text += `\n  Varian: ${String(p.variants).replace(/\n/g, ' ')}`;
        }
      }

      return text;
    }).join('\n\n')
  : '(belum ada produk)';

// Format Basis Pengetahuan Toko
const dataTokoStr = info.length
  ? info.map(k => {
      let konten = k.content.length > 200 ? k.content.substring(0, 200) + '...' : k.content;
      return `- ${k.title}: ${konten}`;
  }).join('\n\n')
  : '(belum ada info)';

// Format Promo
const dataPromoStr = promo.length
  ? promo.map(pr => `- ${pr.title}${pr.description ? `: ${pr.description}` : ''}`).join('\n\n')
  : '(tidak ada promo aktif)';

// Format Riwayat Chat
const riwayatStr = riwayatRaw.length
  ? [...riwayatRaw].reverse().map(m => {
      const sender = m.direction === 'in' ? 'Pelanggan' : 'CS (Kamu)';
      const content = m.type === 'image' ? '[Mengirim Gambar]' : m.body;
      return `${sender}: ${content}`;
    }).join('\n')
  : '(belum ada riwayat)';

// Format Fase
const faseTeks = `Fase Saat Ini: ${fase} | Status Order: ${orderStatus}`;

// Ambil rekening
const rekening = ctx.rekeningTF || '';

// Waktu sekarang (WIB)
const opsiWaktu = { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric', hour: '2-digit', minute: '2-digit', timeZone: 'Asia/Jakarta' };
const waktuSekarang = new Date().toLocaleString('id-ID', opsiWaktu);

return [{
  json: {
    dataBarang: dataBarangStr,
    dataToko: dataTokoStr,
    dataPromo: dataPromoStr,
    riwayat: riwayatStr,
    fase: faseTeks,
    orderStatus: orderStatus,
    rekeningTF: rekening,
    waktuSekarang: waktuSekarang,
  }
}];

const item = $input.first().json;

let raw = item.output ?? item.text ?? item;
let parsed;

try {
  if (typeof raw === 'string') {
    const clean = raw.replace(/```json\s*/gi, '').replace(/```/g, '').trim();
    parsed = JSON.parse(clean);
  } else if (typeof raw === 'object' && raw !== null) {
    parsed = raw;
  } else {
    throw new Error('Output AI bukan string atau objek');
  }
} catch (e) {
  return [{
    json: {
      reply: (typeof raw === 'string' ? raw : '') || 'Maaf, ada kendala. Tim kami akan segera membantu.',
      intent: 'complaint',
      confidence: 30,
      items: null,
      amount: null,
      address: null,
      note: null,
      paymentMethod: null,
      images: [],
    }
  }];
}

// Paksa confidence jadi angka 0-100
let conf = Number(parsed.confidence);
if (!Number.isFinite(conf) || conf < 0 || conf > 100) conf = 50;

// Validasi intent
const validIntents = ['none', 'lead', 'waiting_payment', 'closing', 'complaint'];
const finalIntent = validIntents.includes(parsed.intent) ? parsed.intent : 'none';

// Bersihkan link & data:URI dari reply
let safeReply = String(parsed.reply || '').trim();
safeReply = safeReply
  .replace(/https?:\/\/\S+/g, '')   // hapus http/https
  .replace(/data:image\/\S+/g, '')  // hapus data URI
  .replace(/\\n/g, '\n')            // parse literal \n → newline asli
  .replace(/[^\S\n]{2,}/g, ' ')     // rapikan spasi dobel, jangan sentuh \n
  .trim();

// Validasi images: array {url, caption}. Terima array objek, array string, atau imageUrl tunggal (kompat).
let images = [];
if (Array.isArray(parsed.images)) {
  images = parsed.images.map(it => {
    if (typeof it === 'string') return { url: it.trim(), caption: '' };
    return { url: String(it?.url || '').trim(), caption: String(it?.caption || '').trim() };
  });
} else if (parsed.imageUrl) {
  images = [{ url: String(parsed.imageUrl).trim(), caption: '' }];
}
// Sisakan hanya url valid http/https
images = images.filter(it => /^https?:\/\//i.test(it.url));

// Validasi paymentMethod
const validPay = ['cod', 'tf'];
const paymentMethod = validPay.includes(String(parsed.paymentMethod || '').toLowerCase())
  ? String(parsed.paymentMethod).toLowerCase()
  : null;

// Validasi amount
const amount = parsed.amount != null && Number.isFinite(Number(parsed.amount))
  ? Number(parsed.amount)
  : null;

return [{
  json: {
    reply: safeReply || 'Maaf, ada kendala. Tim kami akan segera membantu.',
    intent: finalIntent,
    confidence: conf,
    items: parsed.items || null,
    amount,
    address: parsed.address || null,
    note: parsed.note || null,
    paymentMethod,
    images,
  }
}];

const raw = $input.all()[0].json[0].content[0].text;
const data = JSON.parse(raw);

return [
  {
    json: {
      is_payment: data.is_payment,
      amount: data.amount,
      sender: data.sender,
      receiver: data.receiver,
      date: data.date,
      time: data.time,
      reference_number: data.reference_number,
      payment_method: data.payment_method,
      status: data.status,
      confidence: data.confidence
    }
  }
];

return ($('Code in JavaScript1').item.json.images || []).map(img => ({
  json: { url: img.url, caption: img.caption }
}));

