const items = $input.all();
const result = {};

let urutan = 1;

for (const item of items) {
  const t = item.json;

  if (t.trigger_text) {
    // Masukin ID (Buat dipanggil di filter Supabase selanjutnya)
    result[`id_${urutan}`] = t.id;

    // Masukin Trigger Text (Buat syarat di Switch)
    result[`kata_kunci_${urutan}`] = t.trigger_text;

    // Masukin yang lainnya sekalian (jaga-jaga kalau butuh)
    result[`reply_text_${urutan}`] = t.reply_text || "";
    result[`image_url_${urutan}`] = t.image_url || "";
    result[`variants_${urutan}`] = t.variants || "";

    urutan++;
  }
}

// Keluarin HANYA 1 ITEM, siap tempur masuk ke Switch!
return [ { json: result } ];

// Ambil data pertama dari node sebelumnya
