// Parse JSON dari Supabase
const parsedVariants = JSON.parse(data.variants);

// Ambil array captions dan finalMessage
const captions = parsedVariants.captions || [];
const finalMessage = parsedVariants.finalMessage || "";

// "Cacah" array captions menjadi item n8n agar bisa di-Loop
const result = captions.map(item => {
  return {
